  size: `${number}x${number}` | undefined;  // e.g., "1024x1024"
  aspectRatio: `${number}:${number}` | undefined;  // e.g., "16:9"
  seed: number | undefined;             // Reproducibility
  files: ImageModelV3File[] | undefined;  // For image editing/variation
