  data: z.array(z.object({
    b64_json: z.string().nullish(),
    url: z.string().nullish(),
  })),
})
```

Full class:
```ts
import { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import {
  combineHeaders,
  createJsonResponseHandler,
  FetchFunction,
  parseProviderOptions,
  postJsonToApi,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { pixelArtFailedResponseHandler } from './pixelart-error';
import { pixelArtImageModelOptions } from './pixelart-image-options';
import { PixelArtImageModelId } from './pixelart-image-settings';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: () => Record<string, string | undefined>;
  fetch?: FetchFunction;
  _internal?: { currentDate?: () => Date };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1;

  get provider() { return this.config.provider; }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({ prompt, n, size, aspectRatio, seed, providerOptions, headers, abortSignal, files, mask }) {
    const warnings: Array<SharedV3Warning> = [];

    if (aspectRatio != null) warnings.push({ type: 'unsupported', feature: 'aspectRatio' });
    if (seed != null) warnings.push({ type: 'unsupported', feature: 'seed' });
    if (files != null) warnings.push({ type: 'unsupported', feature: 'files' });
    if (mask != null) warnings.push({ type: 'unsupported', feature: 'mask' });

    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptions,
    });

    const body: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      n,
      response_format: 'b64_json',
    };

    if (size != null) body.size = size;
    if (pixelArtOptions?.size != null && size == null) body.size = pixelArtOptions.size;
    if (pixelArtOptions?.style != null) body.style = pixelArtOptions.style;
    if (pixelArtOptions?.pixelDensity != null) body.pixel_density = pixelArtOptions.pixelDensity;

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generations`,
      headers: combineHeaders(this.config.headers(), headers),
      body,
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(pixelArtImageResponseSchema),
      abortSignal,
      fetch: this.config.fetch,
    });

    const images = response.data.map(item => item.b64_json!);

    return {
      images,
      warnings,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
    };
  }
}

const pixelArtImageResponseSchema = z.object({
  data: z.array(z.object({
    b64_json: z.string().nullish(),
    url: z.string().nullish(),
  })),
});
```

---

### 10. `packages/pixelart/src/pixelart-provider.ts`

Provider factory. Since this provider is **image-only**, `languageModel` and `embeddingModel` throw `NoSuchModelError` (same pattern XAI uses for embeddings).

Key exports:
- `PixelArtProvider` interface (extends `ProviderV3` shape, with `image` and `imageModel` methods)
- `PixelArtProviderSettings` interface
- `createPixelArt(options?)` factory function
- `pixelart` default export instance

```ts
import { ImageModelV3, NoSuchModelError, ProviderV3 } from '@ai-sdk/provider';
import { FetchFunction, loadApiKey, withoutTrailingSlash, withUserAgentSuffix } from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixelart-image-model';
import { PixelArtImageModelId } from './pixelart-image-settings';
import { VERSION } from './version';

export interface PixelArtProvider extends ProviderV3 {
  image(modelId: PixelArtImageModelId): ImageModelV3;
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;
}

export interface PixelArtProviderSettings {
  baseURL?: string;
  apiKey?: string;
  headers?: Record<string, string>;
  fetch?: FetchFunction;
}

export function createPixelArt(options: PixelArtProviderSettings = {}): PixelArtProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? 'https://api.pixelart.ai/v1');

  const getHeaders = () => withUserAgentSuffix(
    {
      Authorization: `Bearer ${loadApiKey({
        apiKey: options.apiKey,
        environmentVariableName: 'PIXELART_API_KEY',
        description: 'PixelArt',
      })}`,
      ...options.headers,
    },
    `ai-sdk/pixelart/${VERSION}`,
  );

  const createImageModel = (modelId: PixelArtImageModelId) =>
    new PixelArtImageModel(modelId, {
      provider: 'pixelart.image',
      baseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const provider = function (modelId: string) {
    throw new NoSuchModelError({ modelId, modelType: 'languageModel' });
  };

  provider.specificationVersion = 'v3' as const;
  provider.languageModel = (modelId: string) => {
    throw new NoSuchModelError({ modelId, modelType: 'languageModel' });
  };
  provider.embeddingModel = (modelId: string) => {
    throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
  };
  provider.image = createImageModel;
  provider.imageModel = createImageModel;

  return provider as unknown as PixelArtProvider;
}

export const pixelart = createPixelArt();
```

---

### 11. `packages/pixelart/src/index.ts`

Public surface area — exports the factory, default instance, and all public types:

